  window.EXTRA_READ_STORIES.push(...[{"id":"de-morgen","title":"Morgen in der Stadt","subtitle":"Morning in the city","trail":"green-circle","categoryId":"de","sentences":[{"foreign":"Guten Morgen!","en":"Good morning!"},{"foreign":"Hallo. Ich bin gerade angekommen.","en":"Hi. I just arrived."},{"foreign":"Es ist kalt, aber die Sonne scheint.","en":"It's cold, but the sun is shining."},{"foreign":"Ich nehme das Stadtrad durch die Fußgängerzone.","en":"I'm taking the city bike through the pedestrian zone."},{"foreign":"Entschuldigung, wo ist die Haltestelle für die Straßenbahn?","en":"Excuse me, where is the tram stop?"},{"foreign":"Geradeaus, über den Bürgersteig an der Kreuzung.","en":"Straight ahead, across the sidewalk at the intersection."},{"foreign":"Danke. Fährt jetzt eine Linie ins Zentrum?","en":"Thanks. Is a line into the center running now?"},{"foreign":"Ja. Schau auf den Fahrplan, oder nimm ein Taxi, wenn du es eilig hast.","en":"Yes. Check the timetable, or take a taxi if you're in a hurry."},{"foreign":"Vielen Dank. Schönen Tag noch!","en":"Thank you so much. Have a nice day!"},{"foreign":"Kein Problem. Viel Erfolg!","en":"No problem. Good luck!"}],"glosses":{"gerade":"just","angekommen":"arrived","scheint":"is shining","Stadtrad":"city bike","Fußgängerzone":"pedestrian zone","Haltestelle":"stop","Straßenbahn":"tram","geradeaus":"straight ahead","Bürgersteig":"sidewalk","Kreuzung":"intersection","Linie":"line","Zentrum":"center","Fahrplan":"timetable","Taxi":"taxi","eilig":"in a hurry","Viel Erfolg":"good luck"}},{"id":"de-kaffee","title":"Einen Kaffee, bitte","subtitle":"Ordering coffee","trail":"green-circle","categoryId":"de","sentences":[{"foreign":"Hallo! Ist hier im Café noch ein Platz frei?","en":"Hi! Is there a free table here in the café?"},{"foreign":"Ja. Möchtest du die Speisekarte sehen?","en":"Yes. Would you like to look at the menu?"},{"foreign":"Einen Kaffee, bitte. Ohne Milch.","en":"One coffee, please. Without milk."},{"foreign":"Möchtest du auch frühstücken? Wir haben Tee, Saft und Käsebrötchen.","en":"Would you also like to order breakfast? We have tea, juice, and cheese rolls."},{"foreign":"Was empfiehlst du?","en":"What do you recommend?"},{"foreign":"Die vegetarische Suppe ist heute gut. Dessert später, wenn du magst.","en":"The vegetarian soup is good today. Dessert later if you want."},{"foreign":"Ein Käsebrötchen, bitte. Ist es scharf?","en":"A cheese roll, please. Is it spicy?"},{"foreign":"Nein, mild. Wir haben bis drei geöffnet. Zum Mitnehmen geht auch, wenn du es eilig hast.","en":"No, mild. We're open until three. Takeaway is fine if you're in a hurry."},{"foreign":"Kann ich die Rechnung jetzt bekommen? Trinkgeld ist hier okay, oder?","en":"Can I get the bill now? Tipping is okay here, right?"},{"foreign":"Ja. Das macht fünfundvierzig Euro. Schönen Tag noch!","en":"Yes. That's forty-five euros. Have a nice day!"}],"glosses":{"frei":"free","Café":"café","Speisekarte":"menu","Ohne Milch":"without milk","frühstücken":"to have breakfast","Tee":"tea","Saft":"juice","empfiehlst":"recommend","vegetarische":"vegetarian","Käsebrötchen":"cheese roll","Dessert":"dessert","scharf":"spicy","mild":"mild","Mitnehmen":"takeaway","Rechnung":"bill","Trinkgeld":"tip","fünfundvierzig":"forty-five"}},{"id":"de-zug","title":"Im Zug","subtitle":"On the train","trail":"green-circle","categoryId":"de","sentences":[{"foreign":"Fährt dieser Zug nach Berlin?","en":"Does this train go to Berlin?"},{"foreign":"Ja, genau. Gleis vier. Nächste Abfahrt in zehn Minuten.","en":"Yes, that's right. Track four. Next departure in ten minutes."},{"foreign":"Wo kaufe ich eine Fahrkarte? Geht das mit Monatskarte?","en":"Where do I buy a ticket? Can I use a monthly pass?"},{"foreign":"In der App oder am Automaten. Sonst reicht eine einfache Fahrt.","en":"In the app or at the machine. Otherwise a one-way ticket is fine."},{"foreign":"Einfache Fahrt, bitte. Fenster, gerne. Welche Zone ist das?","en":"One-way, please. A window seat, if possible. Which zone is it?"},{"foreign":"Zone eins bis drei. Es gibt etwas Verspätung in der Hauptverkehrszeit.","en":"Zones one to three. There's a bit of a delay in rush hour."},{"foreign":"Wie lange dauert es dann? Ich muss einen Anschluss schaffen.","en":"How long does it take then? I need to make a transfer."},{"foreign":"Ungefähr zwei Stunden. Endstation ist Berlin Hbf.","en":"About two hours. The last stop is Berlin Central."},{"foreign":"Gut. Gibt es Parkplätze am Bahnhof, wenn ich nächstes Mal mit dem Auto komme?","en":"Good. Is there parking at the station if I come by car next time?"},{"foreign":"Ja, aber es kostet. Gute Fahrt!","en":"Yes, but it costs. Have a nice trip!"}],"glosses":{"genau":"that's right","Gleis":"track","Abfahrt":"departure","Fahrkarte":"ticket","Monatskarte":"monthly pass","Automaten":"ticket machine","einfache Fahrt":"one-way","Zone":"zone","Verspätung":"delay","Hauptverkehrszeit":"rush hour","Anschluss":"transfer","ungefähr":"about","Endstation":"terminus","Parkplätze":"parking spaces"}},{"id":"de-bibliothek","title":"In der Bibliothek","subtitle":"At the library","trail":"blue-square","categoryId":"de","sentences":[{"foreign":"Hallo, ich suche einen ruhigen Platz zum Lernen.","en":"Hi, I'm looking for a quiet place to study."},{"foreign":"Oben sind freie Tische am Fenster. Der Seminarraum ist belegt, und das Labor auch.","en":"Upstairs there are free tables by the window. The seminar room is busy, and the lab too."},{"foreign":"Wie lange habt ihr geöffnet?","en":"How late are you open?"},{"foreign":"Bis neun Uhr abends. Der Hörsaal schließt früher.","en":"Until nine in the evening. The lecture hall closes earlier."},{"foreign":"Kann ich mit Studierendenausweis Bücher ausleihen? Ich wohne im Wohnheim gleich nebenan.","en":"Can I borrow books with a student ID? I live in a dorm nearby."},{"foreign":"Ja. Brauchst du etwas von der Leseliste für deinen Kurs?","en":"Yes. Do you need anything from the reading list for your course?"},{"foreign":"Vielleicht später. Zuerst habe ich Gruppenarbeit mit einer Kommilitonin. Kannst du das wiederholen?","en":"Maybe later. First I have group work with a classmate. Could you repeat that?"},{"foreign":"Denk an Notizen. Die Sprechstunde beim Dozenten ist morgen. Die Anmeldung zum Labor ist online.","en":"Remember to take notes. The lecturer's office hours are tomorrow. Lab enrollment is online."},{"foreign":"Danke. Ich hoffe, ich bestehe die Prüfung. Die Abschlussarbeit kommt später.","en":"Thanks. I hope I'll pass the exam. The thesis comes later."},{"foreign":"Viel Erfolg bei der Prüfung nächste Woche!","en":"Good luck with the exam next week!"}],"glosses":{"ruhigen":"quiet","Lernen":"studying","freie":"free","belegt":"busy","Labor":"lab","Hörsaal":"lecture hall","Studierendenausweis":"student ID","Wohnheim":"dorm","Leseliste":"reading list","Kurs":"course","Gruppenarbeit":"group work","Kommilitonin":"classmate","wiederholen":"to repeat","Notizen":"notes","Sprechstunde":"office hours","Dozenten":"lecturer","Anmeldung":"enrollment","bestehe":"pass","Prüfung":"exam","Abschlussarbeit":"thesis"}},{"id":"de-markt","title":"Auf dem Markt","subtitle":"At the market","trail":"blue-square","categoryId":"de","sentences":[{"foreign":"Hallo. Gibt es heute Angebote im Supermarkt?","en":"Hi. Is there a deal at the supermarket today?"},{"foreign":"Ja, Gemüse ist günstig. Hähnchen ist auch im Angebot.","en":"Yes, vegetables are cheap. Chicken is on sale too."},{"foreign":"Was kostet der Käse?","en":"How much is that cheese?"},{"foreign":"Dreißig Euro das Stück. Möchtest du eine Tüte?","en":"Thirty euros each. Would you like a bag?"},{"foreign":"Ja, gerne. Ich nehme zwei Käse und vier Äpfel.","en":"Yes, please. I'll take two cheeses and four apples."},{"foreign":"Der Einkaufswagen steht dort, falls du mehr brauchst. Die Öffnungszeiten stehen an der Tür.","en":"The shopping cart is over there if you need more. Opening hours are on the door."},{"foreign":"Danke. Kann ich an der Kasse mit EC-Karte zahlen, oder mit Kreditkarte?","en":"Thanks. Can I pay with a debit card at the checkout, or a credit card?"},{"foreign":"Beides. Wir sind fast bargeldlos. Hier ist Wechselgeld, falls du welches brauchst.","en":"Either. We're almost cashless. Here's change if you need it."},{"foreign":"Super. Ich suche auch ein Geschenk. Dieser Pullover ist zu groß. Habt ihr eine andere Größe?","en":"Great. I'm also looking for a gift. This sweater is too big. Do you have another size?"},{"foreign":"Die Umkleide ist dort. Du kannst ihn später umtauschen oder zurückgeben.","en":"The fitting room is there. You can exchange it later, or return it."},{"foreign":"Blau ist schön. Tschüss!","en":"Blue is nice. Bye!"}],"glosses":{"Angebote":"deals","Supermarkt":"supermarket","Gemüse":"vegetables","günstig":"cheap","Hähnchen":"chicken","Stück":"each","Tüte":"bag","Einkaufswagen":"shopping cart","Öffnungszeiten":"opening hours","zahlen":"to pay","EC-Karte":"debit card","Kasse":"checkout","bargeldlos":"cashless","Wechselgeld":"change","Geschenk":"gift","Pullover":"sweater","zu groß":"too big","Größe":"size","Umkleide":"fitting room","umtauschen":"to exchange","zurückgeben":"to return"}},{"id":"de-freunde","title":"Neue Freunde","subtitle":"New friends","trail":"blue-square","categoryId":"de","sentences":[{"foreign":"Hallo, ich heiße Sam.","en":"Hi, my name is Sam."},{"foreign":"Schön, dich zu sehen. Ich bin Noor.","en":"Nice to see you. I'm Noor."},{"foreign":"Woher kommst du?","en":"Where are you from?"},{"foreign":"Aus Kanada, aber ich wohne jetzt hier. Und du?","en":"From Canada, but I live here now. And you?"},{"foreign":"Von hier. Was studierst du?","en":"From here. What do you study?"},{"foreign":"Informatik. Hast du Pläne am Wochenende?","en":"Computer science. Do you have plans this weekend?"},{"foreign":"Ja, eine kleine Party bei einem Kumpel. Hast du Zeit? Du bist eingeladen, wenn du willst.","en":"Yes, a small party at a buddy's place. Are you free? You're invited if you want."},{"foreign":"Gerne! Ich hänge gern mit neuen Leuten ab. Mein Hobby ist Fotografie.","en":"I'd love to! I like hanging out with new people. My hobby is photography."},{"foreign":"Super. Es ist sein Geburtstag, also sagen wir alles Gute, und prost!","en":"Really nice. It's his birthday, so we say happy birthday, and cheers!"},{"foreign":"Kaffee nach dem Seminar morgen? Oder Museum am Wochenende?","en":"Coffee after the seminar tomorrow? Or the museum this weekend?"},{"foreign":"Ja. Bis bald. Pass auf dich auf, und bleib in Kontakt!","en":"Yes. See you soon. Take care, and stay in touch!"}],"glosses":{"Schön, dich zu sehen":"nice to see you","Von hier":"from here","Pläne":"plans","Wochenende":"weekend","Party":"party","Kumpel":"buddy","Hast du Zeit":"are you free","eingeladen":"invited","hänge":"hang out","Hobby":"hobby","Fotografie":"photography","Geburtstag":"birthday","alles Gute":"happy birthday / all the best","prost":"cheers","Seminar":"seminar","Bis bald":"see you soon","Pass auf dich auf":"take care","bleib in Kontakt":"stay in touch"}},{"id":"de-job","title":"Erster Arbeitstag","subtitle":"First day at work","trail":"black-diamond","categoryId":"de","sentences":[{"foreign":"Willkommen im Team, Sam. Das ist das Büro.","en":"Welcome to the team, Sam. This is the office."},{"foreign":"Danke. Ich bin etwas nervös. Ist es Vollzeit oder Teilzeit?","en":"Thanks. I'm a bit nervous. Is it full-time or part-time?"},{"foreign":"Vollzeit. Nach der Einstellung stellt der Chef das Projekt vor.","en":"Full-time. After the hire, the boss presents the project."},{"foreign":"Wo kann ich meine Sachen hinstellen?","en":"Where can I put my things?"},{"foreign":"Hier am Fenster ist dein Schreibtisch. Das Passwort bekommst du von einer Kollegin.","en":"Here by the window is your desk. You'll get the password from a coworker."},{"foreign":"Wenn du Fragen hast, frag einfach. Die Tagesordnung liegt im Besprechungsraum.","en":"If you have questions, just ask. The agenda is in the meeting room."},{"foreign":"Verstanden. Wer ist heute meine Ansprechperson?","en":"Understood. Who is my contact person today?"},{"foreign":"Das bin ich. Die Frist für die erste Rechnung an den Kunden ist Freitag.","en":"That's me. The deadline for the first invoice to the client is Friday."},{"foreign":"Ok. Wann kommt das Gehalt, und kann ich ein paar Tage im Homeoffice arbeiten?","en":"Ok. When does the salary come, and can I work from home some days?"},{"foreign":"Gehalt am 15. Sieh dir die Gehaltsabrechnung an. Homeoffice nach der Probezeit.","en":"Salary on the 15th. See the payslip. Home office after the trial period."},{"foreign":"Super. Gibt es später im Jahr eine Dienstreise?","en":"Great. Will there be a business trip later in the year?"},{"foreign":"Möglich. Viel Erfolg!","en":"Possibly. Good luck!"}],"glosses":{"Team":"team","Büro":"office","nervös":"nervous","Vollzeit":"full-time","Teilzeit":"part-time","Einstellung":"hire","Chef":"boss","Projekt":"project","Schreibtisch":"desk","Passwort":"password","Kollegin":"coworker","Tagesordnung":"agenda","Besprechungsraum":"meeting room","Ansprechperson":"contact person","Frist":"deadline","Rechnung":"invoice","Kunden":"client","Gehalt":"salary","Gehaltsabrechnung":"payslip","Homeoffice":"remote work","Probezeit":"trial period","Dienstreise":"business trip"}},{"id":"de-arzt","title":"Beim Arzt","subtitle":"At the doctor's","trail":"black-diamond","categoryId":"de","sentences":[{"foreign":"Guten Tag. Haben Sie jetzt einen Termin?","en":"Good day. Do you have an appointment now?"},{"foreign":"Ja. Was fehlt Ihnen?","en":"Yes. What's the matter?"},{"foreign":"Ich habe seit zwei Tagen Halsschmerzen und Kopfschmerzen. Auch Ohrenschmerzen.","en":"I've had a sore throat for two days, and a headache. Ear pain too."},{"foreign":"Haben Sie Fieber, Husten oder andere Symptome?","en":"Do you have a fever, a cough, or other symptoms?"},{"foreign":"Heute Morgen etwas Fieber, und etwas Husten. Keine Bauchschmerzen.","en":"A little fever this morning, and a bit of a cough. No stomachache."},{"foreign":"Die Krankenschwester misst zuerst den Blutdruck. Sagen Sie aaa.","en":"The nurse will take blood pressure first. Say ah."},{"foreign":"Das sieht nach einer leichten Erkältung aus. Haben Sie Allergien?","en":"It looks like a mild cold. Do you have any allergies?"},{"foreign":"Nein. Brauche ich ein Rezept für Medikamente?","en":"No. Do I need a prescription for medicine?"},{"foreign":"Noch nicht. Ruhe, Wasser und Paracetamol. Kommen Sie wieder, wenn es schlimmer wird.","en":"Not yet. Rest, water, and paracetamol. Come back if it gets worse."},{"foreign":"Vielen Dank. Kann ich eine Krankschreibung bekommen, wenn es schlimmer wird?","en":"Thank you. Can I get a sick note if it gets worse?"},{"foreign":"Ja. Im Notfall: rufen Sie 112 an, oder gehen Sie in die Notaufnahme.","en":"Yes. In an emergency: call 112, or go to A&E / the ER."}],"glosses":{"Termin":"appointment","Halsschmerzen":"sore throat","Kopfschmerzen":"headache","Ohrenschmerzen":"ear pain","Fieber":"fever","Husten":"cough","Symptome":"symptoms","Bauchschmerzen":"stomachache","Krankenschwester":"nurse","Blutdruck":"blood pressure","Erkältung":"cold","Allergien":"allergies","Rezept":"prescription","Medikamente":"medicine","Paracetamol":"paracetamol","Krankschreibung":"sick note","Notfall":"emergency","Notaufnahme":"ER"}},{"id":"de-wohnung","title":"Ein Zimmer suchen","subtitle":"Looking for a room","trail":"black-diamond","categoryId":"de","sentences":[{"foreign":"Hallo, ich rufe wegen der Wohnung im Internet an.","en":"Hi, I'm calling about the apartment online."},{"foreign":"Ja, sie ist noch frei. Wann möchten Sie sie sehen?","en":"Yes, it's still free. When would you like to see it?"},{"foreign":"Heute Nachmittag geht, gegen drei.","en":"This afternoon works, around three."},{"foreign":"Gut. Sie liegt im Viertel, dritter Stock. Es ist eine WG. Sie werden Mieter.","en":"Fine. It's in the neighborhood, third floor. It's a shared flat. You'll be a tenant."},{"foreign":"Gibt es einen Aufzug? Ich habe nur einen Koffer mit Kleidung. Hotel ist langfristig zu teuer.","en":"Is there an elevator? I only have a suitcase with clothes. A hotel is too expensive long-term."},{"foreign":"Nein, nur Treppen. Das Schlafzimmer ist hell, und es gibt einen Balkon.","en":"No, only stairs. The bedroom is bright, and there is a balcony."},{"foreign":"Und das Wohnzimmer und der Waschraum? Irgendwelche undichten Stellen im Bad?","en":"What about the living room and the laundry room? Any leak in the bathroom?"},{"foreign":"Gemeinsam. Kein Leck. Die Miete inklusiv Internet; Nebenkosten extra.","en":"Shared. No leak. The rent includes internet; shared costs come extra."},{"foreign":"Und gibt es eine Kaution? Wann bekomme ich Schlüssel?","en":"And is there a deposit? When do I get keys?"},{"foreign":"Ja, einen Monat. Der Vermieter trifft Sie am Briefkasten mit dem Mietvertrag.","en":"Yes, one month. The landlord will meet you at the mailbox with the lease."},{"foreign":"Super. Sagen Sie Bescheid, wenn der Nachbar sich über Lärm beschwert. Ich bin ruhig.","en":"Great. Let me know if the neighbor complains about noise. I'm quiet."}],"glosses":{"Wohnung":"apartment","frei":"available","Viertel":"neighborhood","WG":"shared flat","Mieter":"tenant","Aufzug":"elevator","Koffer":"suitcase","Hotel":"hotel","Schlafzimmer":"bedroom","Balkon":"balcony","Wohnzimmer":"living room","Waschraum":"laundry room","Leck":"leak","Gemeinsam":"shared","Miete":"rent","Nebenkosten":"shared costs","Kaution":"deposit","Schlüssel":"keys","Vermieter":"landlord","Briefkasten":"mailbox","Mietvertrag":"lease","Nachbar":"neighbor","Lärm":"noise"}},{"id":"de-news","title":"Streik bei der Bahn","subtitle":"Transit strike","trail":"double-black-diamond","categoryId":"de","sentences":[{"foreign":"Hast du heute Morgen die Nachrichten gesehen?","en":"Did you see the news this morning?"},{"foreign":"Nein, was ist passiert?","en":"No, what happened?"},{"foreign":"Morgen streikt die Bahn, und mehrere Linien fallen aus.","en":"Tomorrow there's a strike on the trains, and several lines will stop."},{"foreign":"Also fahren in der Hauptverkehrszeit keine Züge?","en":"So the trains won't run in rush hour?"},{"foreign":"Viele fallen aus. Es gibt Schienenersatzverkehr ab der Endstation.","en":"Many will stop. There will be replacement buses from the terminus."},{"foreign":"Ich nehme das Stadtrad, auch wenn es auf dem Bürgersteig regnet.","en":"I'll take the city bike, even if it rains on the sidewalk."},{"foreign":"Klug. Oder machst du morgen Homeoffice?","en":"Smart. Or are you working from home tomorrow?"},{"foreign":"Vielleicht. Ich spreche zuerst mit der Leitung und prüfe das Budget fürs Taxi.","en":"Maybe. I'll talk to the manager first, and check the budget for a taxi."},{"foreign":"Der Kreisverkehr am Bahnhof wird Chaos. Nimm die Straßenbahn, wenn sie fährt.","en":"The roundabout by the station will be chaos. Take the tram if it runs."},{"foreign":"Okay. Halte mich auf dem Laufenden, wenn die Abfahrt ausfällt.","en":"Alright. Keep me posted if the departure is cancelled."}],"glosses":{"Nachrichten":"news","streikt":"is on strike","Linien":"lines","Hauptverkehrszeit":"rush hour","Schienenersatzverkehr":"replacement bus service","Endstation":"terminus","Stadtrad":"city bike","Bürgersteig":"sidewalk","Homeoffice":"remote work","Leitung":"management","Budget":"budget","Taxi":"taxi","Kreisverkehr":"roundabout","Straßenbahn":"tram","Abfahrt":"departure","ausfällt":"is cancelled"}},{"id":"de-debatte","title":"Eine kurze Debatte","subtitle":"A short debate","trail":"double-black-diamond","categoryId":"de","sentences":[{"foreign":"Ich finde den öffentlichen Nahverkehr wirklich wichtig.","en":"I think public transport is really important."},{"foreign":"Warum?","en":"Why?"},{"foreign":"Weil nicht jeder in der Hauptverkehrszeit ein Auto haben kann, und die Parkgebühren hoch sind.","en":"Because not everyone can have a car in rush hour, and parking fees are high."},{"foreign":"Aber die Busse sind immer voll und verspätet. Der Ticketpreis steigt auch.","en":"But the buses are always full and late. The ticket price is rising too."},{"foreign":"Wenn wir mehr in Linien investieren, wird es besser. Schau dir den städtischen Haushalt an.","en":"If we invest more in lines, it gets better. Look at the city budget."},{"foreign":"Langfristig vielleicht. Gerade jetzt ist es teuer. Zinsen und Kredite belasten die Leute.","en":"In the long run, maybe. Right now it's expensive. Interest and loans put pressure on people."},{"foreign":"Stimmt. Trotzdem finde ich, es lohnt sich. Man kann mehr in den Nahverkehr stecken.","en":"True. Even so, I think it's worth it. You can put more into public transport."},{"foreign":"Lass uns mehr lesen, bevor wir entscheiden. Ich schaue nach dem Mittagessen auf mein Konto.","en":"Let's read more before we decide. I'll check my account after lunch."},{"foreign":"Gut. Wir treffen uns am Geldautomaten am Bahnhof und reden weiter.","en":"Alright. We'll meet at the ATM at the station and talk more."}],"glosses":{"öffentlichen Nahverkehr":"public transport","Hauptverkehrszeit":"rush hour","Parkgebühren":"parking fees","verspätet":"delayed","Ticketpreis":"ticket price","Linien":"lines","Haushalt":"budget","Zinsen":"interest","Kredite":"loans","lohnt sich":"is worth it","Konto":"account","Mittagessen":"lunch","Geldautomaten":"ATM"}},{"id":"de-plaene","title":"Pläne für den Sommer","subtitle":"Summer plans","trail":"double-black-diamond","categoryId":"de","sentences":[{"foreign":"Was machst du im Sommer?","en":"What are you going to do this summer?"},{"foreign":"Ich möchte ein paar Wochen reisen, wenn es klappt. Hast du Pläne?","en":"I want to travel a few weeks, if it works out. Do you have plans?"},{"foreign":"Vielleicht nach Bayern. Ich buche heute Abend hin und zurück in der App.","en":"Maybe to Bavaria. I'm booking a round-trip in the app tonight."},{"foreign":"Hast du den Pass bereit? Das Gepäck muss durch Check-in und Passkontrolle.","en":"Is your passport ready? The luggage has to go through check-in and passport control."},{"foreign":"Ja. Nur Handgepäck. Gate und Sitz stehen auf der Bordkarte nach der Sicherheitskontrolle.","en":"Yes. Hand luggage only. Gate and seat are on the boarding pass after security."},{"foreign":"Das Boarding beginnt früh. Nach der Landung holst du den Koffer am Gepäckband.","en":"Boarding starts early. After landing you pick up the suitcase on the baggage carousel."},{"foreign":"Ich bleibe und mache Überstunden. Das Ersparte geht in mein Budget und in die Kreditraten.","en":"I'm staying and working overtime. The savings go into my budget and loan installments."},{"foreign":"Praktisch. Mein Flug kann Verspätung haben. Die Ankunft ist sowieso spät.","en":"Practical. My flight might be delayed. Arrival is late either way."},{"foreign":"Melde dich, wenn du landest. Das Terminal ist leicht zu finden.","en":"Let me know when you land. The terminal is easy to find."},{"foreign":"Gern. Halte mich auf dem Laufenden. Gute Abfahrt!","en":"Will do. Keep me posted. Have a good departure!"}],"glosses":{"Pläne":"plans","buche":"am booking","hin und zurück":"round-trip","Pass":"passport","Gepäck":"luggage","Check-in":"check-in","Passkontrolle":"passport control","Handgepäck":"hand luggage","Gate":"gate","Sitz":"seat","Bordkarte":"boarding pass","Sicherheitskontrolle":"security","Boarding":"boarding","Gepäckband":"baggage carousel","Überstunden":"overtime","Budget":"budget","Kreditraten":"loan installments","Verspätung":"delay","Ankunft":"arrival","landest":"land","Terminal":"terminal","Abfahrt":"departure"}}]);
